import { solveSudoku } from '@sudoku/sudoku';
import { derived } from 'svelte/store';
import { hints } from './hints';
import { domainGame, invalidCells as invalidCellsStore, puzzleGrid, userGrid as userGridStore } from './game';

function createGrid() {
	return {
		subscribe: puzzleGrid.subscribe,

		generate(difficulty) {
			domainGame.startNew(difficulty);
		},

		decodeSencode(sencode) {
			domainGame.startCustom(sencode);
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode() {
			return domainGame.getSencode();
		},
	};
}

export const grid = createGrid();


function createUserGrid() {
	return {
		subscribe: userGridStore.subscribe,

		set: (pos, value) => {
			domainGame.guess({ row: pos.y, col: pos.x, value });
		},

		applyHint: (pos) => {
			hints.useHint();
			let currentGrid = [];
			const unsubscribe = userGridStore.subscribe(($userGrid) => {
				currentGrid = $userGrid;
			});
			unsubscribe();
			const solvedSudoku = solveSudoku(currentGrid);
			domainGame.guess({
				row: pos.y,
				col: pos.x,
				value: solvedSudoku[pos.y][pos.x],
			});
		},
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(invalidCellsStore, ($invalidCells) => $invalidCells, []);